#ifdef __cplusplus
extern "C" {
#endif

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <cuda_runtime.h>
#include <sys/time.h>

#include "./../main.h"
#include "./../util/timer/timer.h"
#include "timing.h"

extern void kernel_gpu_opencl(par_str d_par_gpu,
					dim_str d_dim_gpu,
					box_str *d_box_gpu,
					FOUR_VECTOR *d_rv_gpu,
					fp *d_qv_gpu,
					FOUR_VECTOR *d_fv_gpu);

extern int platform_id_inuse;
extern int device_id_inuse;

void kernel_gpu_opencl_wrapper(par_str par_cpu,
							dim_str dim_cpu,
							box_str* box_cpu,
							FOUR_VECTOR* rv_cpu,
							fp* qv_cpu,
							FOUR_VECTOR* fv_cpu)
{
	cudaError_t error;

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

	box_str *d_box_gpu;
	FOUR_VECTOR *d_rv_gpu;
	fp *d_qv_gpu;
	FOUR_VECTOR *d_fv_gpu;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

	error = cudaMalloc((void**)&d_box_gpu, dim_cpu.box_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_box_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMalloc((void**)&d_rv_gpu, dim_cpu.space_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_rv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMalloc((void**)&d_qv_gpu, dim_cpu.space_mem2);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_qv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMalloc((void**)&d_fv_gpu, dim_cpu.space_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_fv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif

	error = cudaMemcpy(d_box_gpu, box_cpu, dim_cpu.box_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_box_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMemcpy(d_rv_gpu, rv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_rv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMemcpy(d_qv_gpu, qv_cpu, dim_cpu.space_mem2, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_qv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMemcpy(d_fv_gpu, fv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_fv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	size_t threads_per_block = NUMBER_THREADS;
	size_t blocks_per_grid = dim_cpu.number_boxes;

	printf("# of blocks = %lu, # of threads/block = %lu (ensure that device can handle)\n", (unsigned long)blocks_per_grid, (unsigned long)threads_per_block);

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

	kernel_gpu_opencl<<<blocks_per_grid, threads_per_block>>>(par_cpu, dim_cpu, d_box_gpu, d_rv_gpu, d_qv_gpu, d_fv_gpu);
	error = cudaGetLastError();
	if (error != cudaSuccess) {
		fprintf(stderr, "Kernel launch failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaDeviceSynchronize();
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaDeviceSynchronize failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif

	error = cudaMemcpy(fv_cpu, d_fv_gpu, dim_cpu.space_mem, cudaMemcpyDeviceToHost);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy fv_cpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

	cudaFree(d_rv_gpu);
	cudaFree(d_qv_gpu);
	cudaFree(d_fv_gpu);
	cudaFree(d_box_gpu);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Time spent in different stages of the application:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

#ifdef __cplusplus
}
#endif
